from copy import deepcopy
from typing import Any, Dict, List, Optional
from internbootcamp.src.base_evaluator import BaseEvaluator

def convert_parameter_space_format(parameter_space: Dict[str, Any]) -> Dict[str, Any]:
    """
    将 parameter_space 从旧格式转换为新格式。

    旧格式:
    {
        "idx": 1,
        "comment": "...",
        "space": {
            "w1": [1, 3],
            "w3": [2, 8],
            ...
        }
    }

    新格式:
    {
        "w1": [1, 3],
        "w3": [2, 8],
        ...
    }

    Args:
        parameter_space: 旧格式的 parameter_space 字典

    Returns:
        新格式的 parameter_space 字典
    """
    if not isinstance(parameter_space, dict):
        return parameter_space

    # 如果包含 "space" 字段，说明是旧格式，需要提取 space 内容
    if "space" in parameter_space:
        return parameter_space["space"]

    # 如果包含 "idx" 或 "comment" 字段，移除这些字段后返回
    if "idx" in parameter_space or "comment" in parameter_space:
        new_space = {k: v for k, v in parameter_space.items() 
                    if k not in ["idx", "comment"]}
        return new_space

    # 如果已经是新格式（直接包含参数范围），直接返回
    return parameter_space

class ACSStage1AgentEvaluator(BaseEvaluator):
    """
    ACS Stage1 评估器，继承自 BaseEvaluator

    依赖 acs_interaction.py 和 base_evaluator.py 完成正常的 eval
    重写 _evaluate_one 方法，在调用 interaction_instance.generate_response 时收集 simulation_raw_data
    """

    async def _evaluate_one(
        self,
        input_data: dict,
        client=None,
        api_model=None,
    ) -> dict:
        """
        带 simulation_raw_data 收集的 _evaluate_one 实现
        基本复制父类逻辑，但在调用 interaction_instance.generate_response 时收集 simulation_raw_data
        """
        import uuid

        input_data = deepcopy(input_data)
        data_source = input_data.get("data_source", None)

        if self.bootcamp_registry:
            if data_source and data_source in self.bootcamp_registry:
                config = self.bootcamp_registry[data_source]
                tool_schemas = config["tool_schemas"]
                tool_instances = config["tool_instances"]
                interaction_instance = config["interaction_instance"]
                reward_calculator = config["reward_calculator_class"]
            else:
                print(f"❌ 未找到数据源: {data_source}")
                return None
        else:
            if not self.reward_calculator:
                raise ValueError("必须提供 bootcamp_registry 或 reward_calculator")
            tool_schemas = self.tool_schemas
            tool_instances = self.tool_instances
            interaction_instance = self.interaction
            reward_calculator = self.reward_calculator

        if "messages" in input_data:
            messages = input_data["messages"].copy()
        elif "prompt" in input_data:
            messages = input_data["prompt"].copy()
        else:
            raise ValueError("输入数据必须包含 'messages' 或 'prompt' 字段")
        needed_tools = []
        extra_info = input_data.get("extra_info", {})
        if extra_info.get("need_tools_kwargs") and "tools_kwargs" in extra_info and tool_schemas:
            needed_tool_names = set(extra_info["tools_kwargs"].keys())
            needed_tools = [tool for tool in tool_schemas if tool["function"]["name"] in needed_tool_names]
        payload = self._build_payload({
            "messages": messages,
            "tools": needed_tools,
            "tool_choice": "auto"
        }, api_model=api_model)
        all_payloads = [payload]
        try:
            turn_record = {}
            context_instance_id_dict = {}
            sample_instance_id = str(uuid.uuid4())
            total_prompt_tokens = 0
            total_completion_tokens = 0
            total_tokens = 0
            if tool_instances:
                for tool_name in tool_instances:
                    context_instance_id_dict[tool_name] = sample_instance_id
            if interaction_instance:
                if "interaction_kwargs" in extra_info and "identity" in extra_info["interaction_kwargs"]:
                    identity = extra_info["interaction_kwargs"]["identity"]
                    interaction_instance_id = await interaction_instance.start_interaction(identity=identity)
                else:
                     interaction_instance_id = await interaction_instance.start_interaction()
            else:
                interaction_instance_id = None

            assistant_turn_count = 0
            user_turn_count = 0
            interaction_turn = 0
            prompt_tokens = None
            global_seq_tokens = 0

            # 用于收集所有仿真的原始数据，按照轮次和space idx组织
            # 结构: {turn_0: {space_0: {parameter_space: {...}, parameter_relation_code: "...", simulation_data: [...]}, ...}, ...}
            all_simulation_raw_data = {}

            if "max_turn" in input_data["reward_model"]["ground_truth"]:
                max_turn = int(input_data["reward_model"]["ground_truth"]["max_turn"])
            else:
                max_turn = None

            if max_turn:
                max_user_turns = max_turn + 1
                max_assistant_turns = max_turn + 1
            else:
                max_user_turns = self.max_user_turns
                max_assistant_turns = self.max_assistant_turns

            while max_user_turns is None or user_turn_count < max_user_turns:
                current_assistant_turn_count = 0
                current_tool_calls_executed = 0
                while max_user_turns is None or user_turn_count < max_user_turns:
                    raw_response, usage = await self._call_api(payload, client=client)

                    if prompt_tokens == None:
                        prompt_tokens = usage.get("prompt_tokens", 0)
                    if not prompt_tokens:
                        prompt_tokens = usage.get("prompt_tokens", 0)
                    total_prompt_tokens += usage.get("prompt_tokens", 0)
                    total_completion_tokens += usage.get("completion_tokens", 0)
                    total_tokens += usage.get("total_tokens", 0)
                    global_seq_tokens = usage.get("prompt_tokens", 0) + usage.get("completion_tokens", 0)
                    message = raw_response["choices"][0]["message"]

                    messages.append(message)  
                    tool_calls = message.get("tool_calls", [])
                    assistant_turn_count += 1
                    current_assistant_turn_count += 1
                    turn_record[f"interaction_turn_{interaction_turn}"] = {
                        "assistant_turns": current_assistant_turn_count,
                        "tool_calls_executed": current_tool_calls_executed
                    }
                    if max_assistant_turns is not None and assistant_turn_count >= max_assistant_turns:
                        break

                    if not tool_calls:
                        break
                    else:
                        current_tool_calls_executed += len(tool_calls)
                    context_instance_id_dict,tool_messages,tool_reward,tool_metrics,tool_cumulative_reward = await self._execute_tool_calls(tool_calls, context_instance_id_dict, extra_info, tool_instances)

                    messages.extend(tool_messages)
                    user_turn_count += len(tool_messages)
                    payload = self._build_payload({
                        "messages": messages,
                        "tools": needed_tools,
                        "tool_choice": "auto",
                    }, api_model=api_model)
                    all_payloads.append(payload)

                turn_record[f"interaction_turn_{interaction_turn}"]["tool_calls_executed"] = current_tool_calls_executed
                if max_assistant_turns is not None and assistant_turn_count >= max_assistant_turns:
                    break
                # User响应轮次（通过interaction_instance）- 这里收集 simulation_raw_data
                if interaction_instance:
                    should_terminate_sequence, response_content, current_turn_score, additional_data = await interaction_instance.generate_response(interaction_instance_id, messages)
                    # 收集simulation_raw_data
                    # 注意：即使 simulation_raw_data 为空，也要记录 turn_key，因为中间过程可能没有仿真
                    # 但如果是最后一轮（should_terminate_sequence=True），且没有数据，则不创建 turn_key
                    if additional_data and "simulation_raw_data" in additional_data:
                        current_simulation_data = additional_data["simulation_raw_data"]
                        # 只有当不是最后一轮，或者有数据时，才创建/更新 turn_key
                        if not should_terminate_sequence or (isinstance(current_simulation_data, dict) and len(current_simulation_data) > 0):
                            turn_key = f"turn_{interaction_turn}"
                            if turn_key not in all_simulation_raw_data:
                                all_simulation_raw_data[turn_key] = {}
                            # 合并当前轮次的simulation_raw_data
                            if isinstance(current_simulation_data, dict):
                                all_simulation_raw_data[turn_key].update(current_simulation_data)
                    if should_terminate_sequence:
                        break
                    else:
                        user_turn_count += 1
                        interaction_turn += 1
                        messages.append({
                            "role": "user",
                            "content": response_content
                        })
                else:
                    break
            # 释放工具
            for tool_name,instance_id in context_instance_id_dict.items():
                if instance_id:
                    tool_instance = tool_instances[tool_name]["instance"]
                    await tool_instance.release(instance_id)
            # 清理空的 turn_key（防止有空的 turn 记录）
            all_simulation_raw_data = {
                turn_key: turn_data 
                for turn_key, turn_data in all_simulation_raw_data.items() 
                if len(turn_data) > 0
            }
            # 为每个 turn 中的每个 space 计算 mean_score
            for turn_key, turn_data in all_simulation_raw_data.items():
                for space_key, space_data in turn_data.items():
                    simulation_data = space_data.get("simulation_data", [])
                    if isinstance(simulation_data, list) and len(simulation_data) > 0:
                        # 计算所有 simulation_data 项的 score 均值
                        scores = []
                        for sim_item in simulation_data:
                            if isinstance(sim_item, dict) and "score" in sim_item:
                                score_value = sim_item["score"]
                                # 确保 score 是数值类型
                                if isinstance(score_value, (int, float)):
                                    scores.append(score_value)
                        if len(scores) > 0:
                            mean_score = sum(scores) / len(scores)
                        else:
                            mean_score = -1
                    else:
                        # simulation_data 为空列表，mean_score 为 -1
                        mean_score = -1
                    # 添加 mean_score 字段到 space_data
                    space_data["mean_score"] = mean_score
            # 构建 gene 字段：包含最后一个 turn 的所有 space 的信息
            gene = []
            if all_simulation_raw_data:
                # 找到最后一个 turn（turn_0, turn_1 等中编号最大的）
                turn_keys = list(all_simulation_raw_data.keys())
                if turn_keys:
                    # 按 turn 编号排序，获取最后一个
                    def get_turn_number(turn_key):
                        try:
                            return int(turn_key.split("_")[1])
                        except:
                            return -1
                    turn_keys_sorted = sorted(turn_keys, key=get_turn_number)
                    last_turn_key = turn_keys_sorted[-1]
                    last_turn_data = all_simulation_raw_data[last_turn_key]

                    # 遍历最后一个 turn 中的所有 space
                    for space_key, space_data in last_turn_data.items():
                        parameter_space_raw = space_data.get("parameter_space", {})
                        parameter_relation_code = space_data.get("parameter_relation_code", "")
                        mean_score = space_data.get("mean_score", -1)

                        # 转换 parameter_space 格式
                        parameter_space = convert_parameter_space_format(parameter_space_raw)

                        # 构建 gene 项
                        gene_item = {
                            "variables": {
                                "parameter_space": parameter_space,
                                "parameter_relation_code": parameter_relation_code
                            },
                            "score": mean_score
                        }
                        gene.append(gene_item)
            # 将整个消息上下文转换为字符串用于extract_output
            full_context = self._messages_to_context(messages,tools=needed_tools)
            if "prompt" in input_data:
                response_context = self._messages_to_context(messages[len(input_data["prompt"]):])
            elif "messages" in input_data:
                response_context = self._messages_to_context(messages[len(input_data["messages"]):])
            score = reward_calculator.verify_score(model_output=response_context, identity=input_data["reward_model"]["ground_truth"], **self.verify_correction_kwargs) if reward_calculator else None
            extracted_output = reward_calculator.extract_output(response_context)
            reached_max_turns = (
                (max_assistant_turns is not None and assistant_turn_count >= max_assistant_turns) or
                (max_user_turns is not None and user_turn_count >= max_user_turns)
            )

            # 提取 messages 中前两个回合的 content 并拼接
            base_prompt_for_evolve = ""
            if messages and len(messages) >= 2:
                first_content = messages[0].get("content", "")
                second_content = messages[1].get("content", "")
                # 拼接前两个回合的 content
                base_prompt_for_evolve = f"{first_content}\n{second_content}"
            elif messages and len(messages) >= 1:
                # 如果只有一个消息，只取第一个
                base_prompt_for_evolve = messages[0].get("content", "")

            # 在 input_data 的 extra_info 中添加 base_prompt_for_evolve
            if "extra_info" not in input_data:
                input_data["extra_info"] = {}
            input_data["extra_info"]["base_prompt_for_evolve"] = base_prompt_for_evolve

            return {
                "input": input_data,
                "tools": needed_tools,
                "messages": messages,
                "extracted_output": extracted_output,
                "ground_truth": input_data["reward_model"]["ground_truth"],
                "score": score,
                "reached_max_turns": reached_max_turns,
                "turn_record": turn_record,
                "success": True,
                "full_context": full_context,
                "response_context": response_context,
                "prompt_tokens": prompt_tokens,
                "global_seq_tokens": global_seq_tokens,
                "token_usage": {
                    "prompt_tokens": total_prompt_tokens,
                    "completion_tokens": total_completion_tokens,
                    "total_tokens": total_tokens,
                },
                "evaluation_config": {
                    "model": self.api_model,
                    "api_extra_params": self.api_extra_params,
                    "api_extra_headers": self.api_extra_headers,
                    "max_assistant_turns": max_assistant_turns,
                    "max_user_turns": max_user_turns,
                },
                "simulation_raw_data": all_simulation_raw_data,
                "gene": gene
            }
        except Exception as e:
            import traceback
            traceback.print_exc()
            # 在异常情况下，提取 messages 中前两个回合的 content 并拼接
            base_prompt_for_evolve = ""
            try:
                # 从 input_data 中获取 messages
                error_messages = input_data.get("messages", input_data.get("prompt", []))
                if error_messages and len(error_messages) >= 2:
                    first_content = error_messages[0].get("content", "")
                    second_content = error_messages[1].get("content", "")
                    base_prompt_for_evolve = f"{first_content}\n{second_content}"
                elif error_messages and len(error_messages) >= 1:
                    base_prompt_for_evolve = error_messages[0].get("content", "")
            except:
                pass

            # 在 input_data 的 extra_info 中添加 base_prompt_for_evolve
            if "extra_info" not in input_data:
                input_data["extra_info"] = {}
            input_data["extra_info"]["base_prompt_for_evolve"] = base_prompt_for_evolve

            # 在异常情况下，尝试构建 gene（如果 all_simulation_raw_data 存在）
            gene_error = []
            if 'all_simulation_raw_data' in locals() and all_simulation_raw_data:
                try:
                    turn_keys = list(all_simulation_raw_data.keys())
                    if turn_keys:
                        def get_turn_number(turn_key):
                            try:
                                return int(turn_key.split("_")[1])
                            except:
                                return -1
                        turn_keys_sorted = sorted(turn_keys, key=get_turn_number)
                        last_turn_key = turn_keys_sorted[-1]
                        last_turn_data = all_simulation_raw_data[last_turn_key]
                        for space_key, space_data in last_turn_data.items():
                            parameter_space_raw = space_data.get("parameter_space", {})
                            parameter_relation_code = space_data.get("parameter_relation_code", "")
                            mean_score = space_data.get("mean_score", -1)

                            # 转换 parameter_space 格式
                            parameter_space = convert_parameter_space_format(parameter_space_raw)

                            gene_item = {
                                "variables": {
                                    "parameter_space": parameter_space,
                                    "parameter_relation_code": parameter_relation_code
                                },
                                "score": mean_score
                            }
                            gene_error.append(gene_item)
                except:
                    pass
            return {
                "input": input_data,
                "tools": needed_tools if 'tools' in locals() else [],
                "messages": messages,
                "output": None,
                "score": 0,
                "error": str(e),
                "reached_max_turns": False,
                "turn_record": {},
                "success": False,
                "prompt_tokens": None,
                "global_seq_tokens": None,
                "token_usage": {},
                "evaluation_config": {
                    "model": self.api_model,
                    "api_extra_params": self.api_extra_params,
                    "api_extra_headers": self.api_extra_headers,
                    "max_assistant_turns": max_assistant_turns if 'max_assistant_turns' in locals() else None,
                    "max_user_turns": max_user_turns if 'max_user_turns' in locals() else None,
                },
                "simulation_raw_data": all_simulation_raw_data if 'all_simulation_raw_data' in locals() else {},
                "gene": gene_error
            }
