import json
import re
import ast

INPUT_PATH = "/mnt/shared-storage-user/llmbr-share/hezhishu/internbootcamp_v2/internbootcamp/bootcamps/ACSStage1/data/deepseekv3-2/eval_results_20260129030207_635469.jsonl"
