#        False 表示正常任务 -> 从 response_context 解析 Simulation Result（解析不到则 []）
IS_RANGE_TASK = True


def extract_brace_block(text: str, start_idx: int) -> str:
    assert text[start_idx] == "{"
    depth = 0
    for i in range(start_idx, len(text)):
        if text[i] == "{":
            depth += 1
        elif text[i] == "}":
            depth -= 1
            if depth == 0:
                return text[start_idx : i + 1]
    return text[start_idx:] + ("}" * depth)


def parse_last_block_after_label(ctx: str, label_regex: str, *, optional: bool = False):
    """
    在 ctx 中找到 label_regex 最后一次出现的位置，并从其后提取一个 {...} 块解析为 dict。
    optional=True 时：找不到/解析失败都返回 None，不抛异常。
    """
    ms = list(re.finditer(label_regex, ctx))
    if not ms:
        return None if optional else (_ for _ in ()).throw(ValueError(f"找不到 label: {label_regex}"))

    m = ms[-1]
    start = ctx.find("{", m.end())
    if start == -1:
        return None if optional else (_ for _ in ()).throw(ValueError(f"label 后未找到 '{{': {label_regex}"))

    block = extract_brace_block(ctx, start)
    cleaned = (
        block.replace("true", "True")
        .replace("false", "False")
        .replace("null", "None")
    )

    try:
        return ast.literal_eval(cleaned)
    except Exception:
        return None if optional else (_ for _ in ()).throw(ValueError(f"无法解析 block: {cleaned}"))


def parse_simulation_result_from_response_context(ctx: str):
    return parse_last_block_after_label(ctx, r"Simulation Result:\s*", optional=True)


def get_extra_info(input_obj: dict) -> dict:
    """
    兼容两种位置：
    - input.extra_info
    - input.reward_model.extra_info
    """
    if isinstance(input_obj.get("extra_info"), dict):
        return input_obj["extra_info"]
    rm = input_obj.get("reward_model", {}) or {}
    if isinstance(rm.get("extra_info"), dict):
        return rm["extra_info"]
    return {}


def build_new_id(input_obj: dict) -> str:
    extra = get_extra_info(input_obj)
    generator_name = extra.get("generator_name", None)
    index = extra.get("index", None)
    if generator_name is None or index is None:
        raise ValueError(
            f"缺少 generator_name/index，无法拼 id：generator_name={generator_name}, index={index}"
        )
    return f"{generator_name}_{index}"


def get_base_prompt_for_evolve(input_obj: dict):
    extra = get_extra_info(input_obj)
    if "base_prompt_for_evolve" in extra:
        return extra["base_prompt_for_evolve"]
    if "base_prompt_for_evolve" in input_obj:
        return input_obj["base_prompt_for_evolve"]
    return None


def extract_initial_from_response_context(ep: dict) -> dict:
    input_obj = ep.get("input", {}) or {}
    id_ = build_new_id(input_obj)
    data_source = input_obj.get("data_source", None)
    base_prompt_for_evolve = get_base_prompt_for_evolve(input_obj)

    ctx = ep.get("response_context", "")
    if not ctx:
        raise ValueError("缺少 response_context")

    # initial_parameters：gene 原样（不处理），但去掉可能存在的 turn 字段
    initial_params = ep.get("gene", None)
    if isinstance(initial_params, dict):
        initial_params = dict(initial_params)
        initial_params.pop("turn", None)
    elif isinstance(initial_params, list):
        new_list = []
        for item in initial_params:
            if isinstance(item, dict):
                item = dict(item)
                item.pop("turn", None)
            new_list.append(item)
        initial_params = new_list

    # ✅ initial_res：由开关决定
    if IS_RANGE_TASK:
        initial_res = []
    else:
        initial_res = parse_simulation_result_from_response_context(ctx)
        initial_res = initial_res if initial_res is not None else []

    initial_score = ep.get("score")
    template_input = input_obj

    return {
        "initial_parameters": initial_params,
        "initial_res": initial_res,
        "initial_score": initial_score,
        "id": id_,
        "data_source": data_source,
        "base_prompt_for_evolve": base_prompt_for_evolve,
        "template_input": template_input,
    }


def iter_eps_from_jsonl_line(obj, line_idx: int):
    if isinstance(obj, dict):
        yield obj
    elif isinstance(obj, list):
        for j, ep in enumerate(obj):
            if not isinstance(ep, dict):
                raise ValueError(f"第 {line_idx} 行 list[{j}] 不是 dict，而是 {type(ep)}")
            yield ep
    else:
        raise ValueError(f"第 {line_idx} 行既不是 dict 也不是 list，而是 {type(obj)}")


def main():
    outputs = []
    with open(INPUT_PATH, "r", encoding="utf-8") as f:
        for line_idx, line in enumerate(f):
            line = line.strip()
            if not line:
                continue
            try:
                obj = json.loads(line)
            except Exception as e:
                raise ValueError(f"第 {line_idx} 行不是合法 JSON: {e}")

            for j, ep in enumerate(iter_eps_from_jsonl_line(obj, line_idx)):
                try:
                    data = extract_initial_from_response_context(ep)
                except Exception as e:
                    raise RuntimeError(f"解析失败：line={line_idx}, idx={j}, err={e}")
                outputs.append([data])  # [[{data}], [{data}], ...]

    with open(OUTPUT_PATH, "w", encoding="utf-8") as f:
        json.dump(outputs, f, ensure_ascii=False, indent=2)

    print(f"[OK] 已写入 {len(outputs)} 条数据（格式 [[{{data}}],...]) → {OUTPUT_PATH}")


if __name__ == "__main__":
    main()
